{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type":    "prompt",
            "prompt":  "Does this Bash command look destructive or irreversible? Answer yes or no.",
            "timeout": 30
          }
        ]
      }
    ]
  }
}
